package com.hospital.management.controller.billing;import com.hospital.management.service.*;import com.hospital.management.service.impl.BillServiceImpl;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/billing/status")public class BillStatusServlet extends HttpServlet{private final BillService service;public BillStatusServlet(){this(new BillServiceImpl());}public BillStatusServlet(BillService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws IOException{r.sendError(405);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws IOException{Long id=BillingRequest.id(q.getParameter("billId"));if(id==null||!"cancel".equals(q.getParameter("action"))){r.sendError(400);return;}ServiceResult<Void>x=service.cancelBill(id,BillingRequest.audit(q),BillingRequest.user(q));r.sendRedirect(q.getContextPath()+"/billing/view?id="+id+"&"+(x.isSuccess()?"message=cancelled":"error=cancel"));}}
